const listAgentRuntimeBindings = `-- name: ListAgentRuntimeBindings :many
SELECT
    b.id,
    b.agent_id,
    b.runtime_id,
    b.priority,
    b.enabled,
    b.created_by,
    b.created_at,
    b.updated_at,
    r.name AS runtime_name,
    r.custom_name AS runtime_custom_name,
    r.provider,
    r.profile_id,
    r.daemon_id,
    r.runtime_mode,
    r.status AS runtime_status,
    r.owner_id AS runtime_owner_id,
    COALESCE(active.active_count, 0)::integer AS active_task_count
FROM agent_runtime_binding b
JOIN agent_runtime r ON r.id = b.runtime_id
LEFT JOIN LATERAL (
    SELECT count(*) AS active_count
    FROM agent_task_queue t
    WHERE t.runtime_id = r.id
      AND t.status IN ('queued', 'dispatched', 'running', 'waiting_local_directory')
) active ON TRUE
WHERE b.agent_id = $1
ORDER BY b.priority ASC, b.runtime_id ASC
`

type ListAgentRuntimeBindingsRow struct {
	ID                pgtype.UUID        `json:"id"`
	AgentID           pgtype.UUID        `json:"agent_id"`
	RuntimeID         pgtype.UUID        `json:"runtime_id"`
	Priority          int32              `json:"priority"`
	Enabled           bool               `json:"enabled"`
	CreatedBy         pgtype.UUID        `json:"created_by"`
	CreatedAt         pgtype.Timestamptz `json:"created_at"`
	UpdatedAt         pgtype.Timestamptz `json:"updated_at"`
	RuntimeName       string             `json:"runtime_name"`
	RuntimeCustomName pgtype.Text        `json:"runtime_custom_name"`
	Provider          string             `json:"provider"`
	ProfileID         pgtype.UUID        `json:"profile_id"`
	DaemonID          pgtype.Text        `json:"daemon_id"`
	RuntimeMode       string             `json:"runtime_mode"`
	RuntimeStatus     string             `json:"runtime_status"`
	RuntimeOwnerID    pgtype.UUID        `json:"runtime_owner_id"`
	ActiveTaskCount   int32              `json:"active_task_count"`
}

func (q *Queries) ListAgentRuntimeBindings(ctx context.Context, agentID pgtype.UUID) ([]ListAgentRuntimeBindingsRow, error) {
	rows, err := q.db.Query(ctx, listAgentRuntimeBindings, agentID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []ListAgentRuntimeBindingsRow{}
	for rows.Next() {
		var i ListAgentRuntimeBindingsRow
		if err := rows.Scan(
			&i.ID,
			&i.AgentID,
			&i.RuntimeID,
			&i.Priority,
			&i.Enabled,
			&i.CreatedBy,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.RuntimeName,
			&i.RuntimeCustomName,
			&i.Provider,
			&i.ProfileID,
			&i.DaemonID,
			&i.RuntimeMode,
			&i.RuntimeStatus,
			&i.RuntimeOwnerID,
			&i.ActiveTaskCount,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

