const selectManagedRuntimeForAgent = `-- name: SelectManagedRuntimeForAgent :one
SELECT r.id, r.workspace_id, r.daemon_id, r.name, r.runtime_mode, r.provider, r.status, r.device_info, r.metadata, r.last_seen_at, r.created_at, r.updated_at, r.owner_id, r.legacy_daemon_id, r.visibility, r.profile_id, r.custom_name
FROM agent_runtime_binding b
JOIN agent_runtime r ON r.id = b.runtime_id
JOIN agent a ON a.id = b.agent_id
LEFT JOIN LATERAL (
    SELECT count(*) AS active_count
    FROM agent_task_queue t
    WHERE t.runtime_id = r.id
      AND t.status IN ('queued', 'dispatched', 'running', 'waiting_local_directory')
) active ON TRUE
WHERE b.agent_id = $1
  AND b.enabled = TRUE
  AND r.status = 'online'
ORDER BY
    CASE WHEN r.id = a.runtime_id THEN 0 ELSE 1 END,
    b.priority ASC,
    COALESCE(active.active_count, 0) ASC,
    r.id ASC
LIMIT 1
`

